class InputValidator {

    private static final Pattern ALPHANUMERIC_PATTERN = Pattern.compile("^[a-zA-Z0-9\\-]+$");
    private static final Pattern ITEM_NAME_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s\\-_.]+$");
    private static final Pattern ADDRESS_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s,\\.\\-#]+$");

    private static final int MAX_CUSTOMER_ID_LENGTH = 50;
    private static final int MAX_ITEM_ID_LENGTH = 50;
    private static final int MAX_ITEM_NAME_LENGTH = 200;
    private static final int MAX_ADDRESS_LENGTH = 500;
    private static final int MAX_ITEMS_PER_ORDER = 100;
    private static final int MAX_QUANTITY_PER_ITEM = 10000;
    private static final BigDecimal MAX_UNIT_PRICE = new BigDecimal("999999.99");
    private static final BigDecimal MIN_UNIT_PRICE = new BigDecimal("0.01");

    private static final Set<String> ALLOWED_CURRENCIES;
    static {
        Set<String> currencies = new HashSet<>();
        currencies.add("USD");
        currencies.add("EUR");
        currencies.add("GBP");
        currencies.add("CAD");
        currencies.add("AUD");
        ALLOWED_CURRENCIES = Collections.unmodifiableSet(currencies);
    }

    public static void validateOrderRequest(OrderRequest request) {
        if (request == null) {
            throw new IllegalArgumentException("Order request must not be null");
        }

        validateCustomerId(request.getCustomerId());
        validateApiKey(request.getCustomerApiKey());
        validateItems(request.getItems());
        validateShippingAddress(request.getShippingAddress());
        validateCurrency(request.getCurrency());
    }

    private static void validateCustomerId(String customerId) {
        if (customerId == null || customerId.trim().isEmpty()) {
            throw new IllegalArgumentException("Customer ID is required");
        }
        if (customerId.length() > MAX_CUSTOMER_ID_LENGTH) {
            throw new IllegalArgumentException("Customer ID exceeds maximum length");
        }
        if (!ALPHANUMERIC_PATTERN.matcher(customerId).matches()) {
            throw new IllegalArgumentException("Customer ID contains invalid characters");
        }
    }

    private static void validateApiKey(String apiKey) {
        if (apiKey == null || apiKey.trim().isEmpty()) {
            throw new IllegalArgumentException("API key is required");
        }
        if (!ALPHANUMERIC_PATTERN.matcher(apiKey).matches()) {
            throw new IllegalArgumentException("API key contains invalid characters");
        }
    }

    private static void validateItems(List<OrderItem> items) {
        if (items == null || items.isEmpty()) {
            throw new IllegalArgumentException("Order must contain at least one item");
        }
        if (items.size() > MAX_ITEMS_PER_ORDER) {
            throw new IllegalArgumentException("Order exceeds maximum number of items (" + MAX_ITEMS_PER_ORDER + ")");
        }

        Set<String> seenItemIds = new HashSet<>();
        for (OrderItem item : items) {
            validateOrderItem(item, seenItemIds);
        }
    }

    private static void validateOrderItem(OrderItem item, Set<String> seenItemIds) {
        if (item == null) {
            throw new IllegalArgumentException("Order item must not be null");
        }

        // Validate item ID
        if (item.getItemId() == null || item.getItemId().trim().isEmpty()) {
            throw new IllegalArgumentException("Item ID is required");
        }
        if (item.getItemId().length() > MAX_ITEM_ID_LENGTH) {
            throw new IllegalArgumentException("Item ID exceeds maximum length");
        }
        if (!ALPHANUMERIC_PATTERN.matcher(item.getItemId()).matches()) {
            throw new IllegalArgumentException("Item ID contains invalid characters");
        }

        // Check for duplicate item IDs
        if (!seenItemIds.add(item.getItemId())) {
            throw new IllegalArgumentException("Duplicate item ID: items should be consolidated");
        }

        // Validate item name
        if (item.getItemName() == null || item.getItemName().trim().isEmpty()) {
            throw new IllegalArgumentException("Item name is required");
        }
        if (item.getItemName().length() > MAX_ITEM_NAME_LENGTH) {
            throw new IllegalArgumentException("Item name exceeds maximum length");
        }
        if (!ITEM_NAME_PATTERN.matcher(item.getItemName()).matches()) {
            throw new IllegalArgumentException("Item name contains invalid characters");
        }

        // Validate quantity
        if (item.getQuantity() <= 0) {
            throw new IllegalArgumentException("Item quantity must be positive");
        }
        if (item.getQuantity() > MAX_QUANTITY_PER_ITEM) {
            throw new IllegalArgumentException("Item quantity exceeds maximum allowed (" + MAX_QUANTITY_PER_ITEM + ")");
        }

        // Validate unit price
        if (item.getUnitPrice() == null) {
            throw new IllegalArgumentException("Unit price is required");
        }
        if (item.getUnitPrice().compareTo(MIN_UNIT_PRICE) < 0) {
            throw new IllegalArgumentException("Unit price must be at least " + MIN_UNIT_PRICE);
        }
        if (item.getUnitPrice().compareTo(MAX_UNIT_PRICE) > 0) {
            throw new IllegalArgumentException("Unit price exceeds maximum allowed (" + MAX_UNIT_PRICE + ")");
        }
        if (item.getUnitPrice().scale() > 2) {
            throw new IllegalArgumentException("Unit price must have at most 2 decimal places");
        }
    }

    private static void validateShippingAddress(String address) {
        if (address == null || address.trim().isEmpty()) {
            throw new IllegalArgumentException("Shipping address is required");
        }
        if (address.length() > MAX_ADDRESS_LENGTH) {
            throw new IllegalArgumentException("Shipping address exceeds maximum length");
        }
        if (!ADDRESS_PATTERN.matcher(address).matches()) {
            throw new IllegalArgumentException("Shipping address contains invalid characters");
        }
    }

    private static void validateCurrency(String currency) {
        if (currency == null || currency.trim().isEmpty()) {
            throw new IllegalArgumentException("Currency is required");
        }
        if (!ALLOWED_CURRENCIES.contains(currency.toUpperCase())) {
            throw new IllegalArgumentException("Currency not supported. Allowed: " + ALLOWED_CURRENCIES);
        }
    }
}

