        List<OrderItem> items = new ArrayList<>();

        // Item with correct catalog price
        OrderItem item1 = new OrderItem("ITEM-001", "Widget A", new BigDecimal("29.99"), 5);
        items.add(item1);

        // Item with TAMPERED price (client tries to submit $1.00 instead of $49.99)
