        OrderItem item2 = new OrderItem("ITEM-002", "Widget B", new BigDecimal("1.00"), 3);
        items.add(item2);

        OrderItem item3 = new OrderItem("ITEM-003", "Widget C", new BigDecimal("9.99"), 10);
